mapper.select:
SELECT o.order_id AS orderId, o.user_no AS userNo, u.name AS customerName, u.tel AS tel, DATE_FORMAT(o.order_time, '%H:%i') AS orderDate, o.amount AS totalPrice, o.order_state AS state, o.address AS address, o.request AS request, GROUP_CONCAT(CONCAT(od.menu_name, ' x', od.quantity) SEPARATOR ', ') AS menuList FROM orders o JOIN order_detail od ON o.order_id = od.order_id JOIN user u ON o.user_no = u.user_no WHERE o.store_id = #{storeId}
AND o.order_state = #{state}
AND DATE(o.order_time) = #{date}
GROUP BY o.order_id ORDER BY o.order_time DESC

mapper.update:
UPDATE orders
SET order_state = #{orderState}
WHERE order_id = #{orderId}

mapper.insert:
INSERT INTO store_category (store_id, category_id)
SELECT store_id, #{categoryId}
FROM store
WHERE owner_id = #{userId}
ORDER BY store_id DESC
    LIMIT 1

mapper.update:
UPDATE menu_category
SET category = #{category}
WHERE category_id = #{categoryId}
